import React, { useState, useEffect } from 'react';
import api from '../services/api';

function SettlementList({ refreshTrigger, onConfirm }) {
  const [settlements, setSettlements] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadSettlements();
  }, [refreshTrigger]);

  const loadSettlements = async () => {
    setLoading(true);
    try {
      const data = await api.getSettlements();
      setSettlements(data);
    } catch (error) {
      console.error('Error loading settlements:', error);
    } finally {
      setLoading(false);
    }
  };

  const confirmSettlement = async (id) => {
    if (window.confirm('Confirm that you received this payment?')) {
      try {
        await api.confirmSettlement(id);
        alert('✓ Payment confirmed! The balance has been updated.');
        onConfirm();
        loadSettlements();
      } catch (error) {
        console.error('Error confirming settlement:', error);
        alert(error.response?.data?.error || 'Error confirming settlement');
      }
    }
  };

  const deleteSettlement = async (id) => {
    if (window.confirm('Are you sure you want to delete this settlement? This action cannot be undone.')) {
      try {
        const response = await fetch(`http://localhost:5000/api/settlements/${id}`, {
          method: 'DELETE'
        });
        if (response.ok) {
          alert('Settlement deleted');
          onConfirm();
          loadSettlements();
        } else {
          alert('Error deleting settlement');
        }
      } catch (error) {
        console.error('Error deleting settlement:', error);
        alert('Error deleting settlement');
      }
    }
  };

  // Separate pending and confirmed
  const pendingSettlements = settlements.filter(s => s.confirmed === 0);
  const confirmedSettlements = settlements.filter(s => s.confirmed === 1);

  if (loading) {
    return <div>Loading settlements...</div>;
  }

  return (
    <div>
      <h2>Settlement History</h2>
      
      {pendingSettlements.length > 0 && (
        <div className="card" style={{ background: '#fef3c7' }}>
          <h3>⏳ Pending Confirmations</h3>
          <p style={{ fontSize: '0.9em', color: '#666', marginBottom: '15px' }}>
            These payments need your confirmation if you're the receiver
          </p>
          {pendingSettlements.map(settlement => (
            <div key={settlement.id} style={{
              padding: '15px',
              margin: '10px 0',
              background: '#fffbeb',
              borderRadius: '8px',
              border: '1px solid #fde68a'
            }}>
              <p>
                <strong>{settlement.from_name}</strong> paid <strong>{settlement.to_name}</strong>
              </p>
              <p className="balance-positive">Amount: ${settlement.amount.toFixed(2)}</p>
              <p>Date: {settlement.date}</p>
              <div style={{ display: 'flex', gap: '10px', marginTop: '10px' }}>
                {settlement.to_name === localStorage.getItem('currentUser') && (
                  <button 
                    onClick={() => confirmSettlement(settlement.id)}
                    style={{ background: '#10b981' }}
                  >
                    ✓ Confirm Receipt
                  </button>
                )}
                <button 
                  onClick={() => deleteSettlement(settlement.id)}
                  style={{ background: '#ef4444' }}
                >
                  Delete
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {confirmedSettlements.length > 0 && (
        <div className="card">
          <h3>✅ Completed Settlements</h3>
          {confirmedSettlements.map(settlement => (
            <div key={settlement.id} style={{
              padding: '12px',
              margin: '8px 0',
              background: '#d1fae5',
              borderRadius: '6px',
              border: '1px solid #a7f3d0'
            }}>
              <p>
                <strong>{settlement.from_name}</strong> paid <strong>{settlement.to_name}</strong>
                <span className="balance-positive"> ${settlement.amount.toFixed(2)}</span>
              </p>
              <p style={{ fontSize: '0.8em', color: '#666' }}>Confirmed on: {settlement.date}</p>
            </div>
          ))}
        </div>
      )}

      {settlements.length === 0 && (
        <p>No settlements recorded yet.</p>
      )}
    </div>
  );
}

export default SettlementList;
